<?php
$pageTitle='Work Centers & Routings';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('work_centers');
$pdo=getDB();
$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='center'){
      $code=trim((string)$_POST['center_code']); if($code===''){$code=nextScopedDocumentNumber($pdo,'work_center',setting('work_center_prefix','WC'),operationalScope($pdo));}
      $pdo->prepare('INSERT INTO '.table('manufacturing_work_centers').' (center_code,center_name,center_type,hourly_rate,capacity_hours_per_day,status,notes) VALUES (?,?,?,?,?,"active",?)')->execute([$code,trim((string)$_POST['center_name']),trim((string)$_POST['center_type']),max(0,(float)$_POST['hourly_rate']),max(0,(float)$_POST['capacity_hours_per_day']),trim((string)$_POST['notes'])]);
      flash('success','Work center created.');
    }elseif($action==='routing'){
      $code=trim((string)$_POST['routing_code']);
      $pdo->prepare('INSERT INTO '.table('manufacturing_routings').' (routing_code,routing_name,product_id,status,notes) VALUES (?,?,?,"active",?)')->execute([$code,trim((string)$_POST['routing_name']),(int)$_POST['product_id']?:null,trim((string)$_POST['notes'])]);
      flash('success','Routing created.');
    }elseif($action==='step'){
      $pdo->prepare('INSERT INTO '.table('manufacturing_routing_steps').' (manufacturing_routing_id,step_number,work_center_id,operation_name,standard_minutes,labor_rate,notes) VALUES (?,?,?,?,?,?,?)')->execute([(int)$_POST['routing_id'],(int)$_POST['step_number'],(int)$_POST['work_center_id']?:null,trim((string)$_POST['operation_name']),max(0,(float)$_POST['standard_minutes']),max(0,(float)$_POST['labor_rate']),trim((string)$_POST['notes'])]);
      flash('success','Routing step added.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'work-centers']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/work-centers.php');
}
$centers=$pdo->query('SELECT * FROM '.table('manufacturing_work_centers').' ORDER BY center_code')->fetchAll();
$routings=$pdo->query('SELECT r.*,p.name product_name FROM '.table('manufacturing_routings').' r LEFT JOIN '.table('products').' p ON p.id=r.product_id ORDER BY r.created_at DESC')->fetchAll();
$steps=$pdo->query('SELECT s.*,r.routing_code,w.center_code FROM '.table('manufacturing_routing_steps').' s LEFT JOIN '.table('manufacturing_routings').' r ON r.id=s.manufacturing_routing_id LEFT JOIN '.table('manufacturing_work_centers').' w ON w.id=s.work_center_id ORDER BY r.routing_code,s.step_number')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Routing Master Data</div><h2 class="h4 mb-1">Work Centers & Routings</h2><p class="text-secondary mb-0">Define labor stations, hourly rates, production routing, and standard operation time.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="center"><h2 class="h5 mb-3">Create Work Center</h2><input class="form-control mb-2" name="center_code" placeholder="Auto/manual code"><input class="form-control mb-2" name="center_name" placeholder="Center name"><input class="form-control mb-2" name="center_type" value="general"><input class="form-control mb-2" type="number" step="0.01" name="hourly_rate" placeholder="Hourly rate"><input class="form-control mb-2" type="number" step="0.01" name="capacity_hours_per_day" value="8"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Center</button></form><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="routing"><h2 class="h5 mb-3">Create Routing</h2><input class="form-control mb-2" name="routing_code" placeholder="ROUTE-001"><input class="form-control mb-2" name="routing_name" placeholder="Routing name"><select class="form-select mb-2" name="product_id"><option value="0">No product</option><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Create Routing</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="step"><h2 class="h5 mb-3">Add Routing Step</h2><select class="form-select mb-2" name="routing_id"><?php foreach($routings as $r): ?><option value="<?php echo (int)$r['id']; ?>"><?php echo esc($r['routing_code'].' · '.$r['routing_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" name="step_number" value="10"><select class="form-select mb-2" name="work_center_id"><option value="0">No center</option><?php foreach($centers as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['center_code'].' · '.$c['center_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="operation_name" placeholder="Operation"><input class="form-control mb-2" type="number" step="0.01" name="standard_minutes" placeholder="Standard minutes"><input class="form-control mb-2" type="number" step="0.01" name="labor_rate" placeholder="Labor rate"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-success w-100">Add Step</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Work Centers</h2><table class="table"><thead><tr><th>Code</th><th>Name</th><th>Rate</th><th>Capacity</th></tr></thead><tbody><?php foreach($centers as $c): ?><tr><td><strong><?php echo esc($c['center_code']); ?></strong></td><td><?php echo esc($c['center_name']); ?></td><td><?php echo money($c['hourly_rate']); ?></td><td><?php echo number_format((float)$c['capacity_hours_per_day'],2); ?>h/day</td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Routing Steps</h2><table class="table"><thead><tr><th>Routing</th><th>Step</th><th>Center</th><th>Operation</th><th>Minutes</th><th>Rate</th></tr></thead><tbody><?php foreach($steps as $s): ?><tr><td><?php echo esc($s['routing_code']); ?></td><td><?php echo (int)$s['step_number']; ?></td><td><?php echo esc($s['center_code']); ?></td><td><?php echo esc($s['operation_name']); ?></td><td><?php echo number_format((float)$s['standard_minutes'],2); ?></td><td><?php echo money($s['labor_rate']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>